                      </div>
                      <button onClick={() => setVacations(vacations.filter(vac => vac.id !== v.id))} className="text-rose-400 p-2 hover:bg-rose-50 rounded-full group-hover:scale-110 transition-transform">
                        <Trash2 size={16}/>
