                    <button 
                      key={t}
                      onClick={() => setVacationType(t)}
                      className={`py-3 rounded-xl text-sm font-bold transition-all ${vacationType === t ? 'bg-indigo-600 text-white scale-105' : 'bg-gray-100 text-gray-500'}`}
                    >
                      {t}
                    </button>
                  ))}
