    const ws = XLSX.utils.aoa_to_sheet(wsData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "AttendanceHistory");
    XLSX.writeFile(wb, `Attendance_History_${historySelectedDate}.xlsx`);
