    const ws = XLSX.utils.aoa_to_sheet(wsData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "VacationsList");
    XLSX.writeFile(wb, `SoftRose_Vacations_${new Date().toLocaleDateString()}.xlsx`);
