              <div className="space-y-2">
                <label className="text-xs font-bold opacity-60">اختر الموظف</label>
                <select value={selectedEmployeeId} onChange={e => setSelectedEmployeeId(e.target.value)} className="w-full p-4 bg-gray-100 rounded-2xl outline-none font-bold text-black focus:ring-2 ring-indigo-500 transition-all">
                  <option value="">-- اختر الموظف --</option>
                  {employees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}
                </select>
              </div>
              <button onClick={handleAddVacation} disabled={!selectedEmployeeId} className={`w-full py-4 rounded-2xl font-black text-lg shadow-xl active:scale-95 transition-all ${selectedEmployeeId ? 'bg-indigo-600 text-white hover:bg-indigo-700' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}>
                {editingVacationId ? 'تعديل الإجازة ومزامنة الجدول' : 'تأكيد وتسجيل الفترة'}
              </button>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-black/5 border-t p-3 text-center text-[10px] opacity-40 shrink-0">
        SOFT ROSE MANAGEMENT SYSTEM &bull; v2.6 &copy; 2025
      </footer>
    </div>
  );
}

import { DAYS_ARABIC } from './constants';
import { AttendanceRecord, Vacation } from './types';

export const generateRandomTime = (startHour: number, startMin: number, endHour: number, endMin: number): string => {
  const start = startHour * 60 + startMin;
  const end = endHour * 60 + endMin;
  const randomTotalMinutes = Math.floor(Math.random() * (end - start + 1)) + start;

  const h = Math.floor(randomTotalMinutes / 60);
  const m = randomTotalMinutes % 60;

  // إرجاع الوقت بتنسيق 24 ساعة (ساعة:دقيقة) بدون أي لاحقة (مثل 16:45 بدلاً من 4:45 م)
  return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}`;
};

export const parseDate = (dateStr: string): Date => {
  const [day, month, year] = dateStr.split('/').map(Number);
  return new Date(year, month - 1, day);
};

export const formatDate = (date: Date): string => {
  const d = date.getDate().toString().padStart(2, '0');
  const m = (date.getMonth() + 1).toString().padStart(2, '0');
  const y = date.getFullYear();
  return `${d}/${m}/${y}`;
};

export const getCycleLabel = (dateStr: string): string => {
  const date = parseDate(dateStr);
  const day = date.getDate();
  const month = date.getMonth() + 1;
  const year = date.getFullYear();

  if (day >= 21) {
    const nextMonth = month === 12 ? 1 : month + 1;
    const nextYear = month === 12 ? year + 1 : year;
    return `دورة: 21 / ${month} / ${year} إلى 20 / ${nextMonth} / ${nextYear}`;
  } else {
    const prevMonth = month === 1 ? 12 : month - 1;
    const prevYear = month === 1 ? year - 1 : year;
    return `دورة: 21 / ${prevMonth} / ${prevYear} إلى 20 / ${month} / ${year}`;
  }
};

export const generateAttendanceCycle = (
  startMonth: number, 
  year: number, 
  employeeId: string, 
  employeeName: string,
  vacations: Vacation[]
): AttendanceRecord[] => {
  const records: AttendanceRecord[] = [];

  let currentDate = new Date(year, startMonth - 1, 21);
  const endDate = new Date(year, startMonth, 20);

  const employeeVacations = vacations.filter(v => v.employeeId === employeeId);

  while (currentDate <= endDate) {
    const dayIndex = currentDate.getDay(); // 0 (Sun) to 6 (Sat)
    const dayName = DAYS_ARABIC[dayIndex];
    const dateStr = formatDate(currentDate);

    // 1. Check for manual vacations
    const manualVacation = employeeVacations.find(v => v.date === dateStr);

    // 2. Check for fixed weekly holidays
    let isWeeklyHoliday = false;
    if (employeeName === 'اسماء صالح') {
      if (dayIndex === 2) isWeeklyHoliday = true; // الثلاثاء
    } else if (employeeName === 'ملك هيثم') {
      if (dayIndex === 1) isWeeklyHoliday = true; // الاثنين
    } else if (employeeName === 'امنيه اشرف') {
      if (dayIndex === 0) isWeeklyHoliday = true; // الأحد
    } else {
      if (dayIndex === 5) isWeeklyHoliday = true; // الجمعة (الباقي)
    }

    let checkIn = "";
    let checkOut = "";
    let note = "";

    if (manualVacation) {
      checkIn = "اجازه";
      checkOut = manualVacation.type;
      note = manualVacation.deductFromSalary ? "تخصم من الراتب" : "";
    } else if (isWeeklyHoliday) {
      checkIn = "راحة إسبوعية";
      checkOut = "-";
      note = "";
    } else {
      checkIn = generateRandomTime(9, 0, 9, 45);
      checkOut = generateRandomTime(16, 45, 18, 14);
      note = "";
    }

    records.push({
      id: Math.random().toString(36).substr(2, 9),
      employeeId,
      employeeName,
      day: dayName,
      date: dateStr,
      checkIn,
      checkOut,
      notes: note,
      cycleMonth: startMonth,
      cycleYear: year
    });

    currentDate.setDate(currentDate.getDate() + 1);
  }

  return records;
};

export const copyToClipboard = async (text: string) => {
  try {
    await navigator.clipboard.writeText(text);
    return true;
  } catch (err) {
    console.error('Failed to copy: ', err);
    return false;
  }
};

